### Create Supabase Server Client for Server Components in TypeScript

Source: https://github.com/supabase/supabase/blob/master/apps/www/_blog/2024-01-12-react-query-nextjs-app-router-cache-helpers.mdx

This TypeScript function facilitates the creation of a Supabase client tailored for Next.js server components, utilizing 'createServerClient' from '@supabase/ssr'. It integrates with Next.js 'cookies' to manage authentication tokens, enabling secure and stateful Supabase interactions from the server side, crucial for Row Level Security (RLS).

```ts
import { createServerClient } from '@supabase/ssr'
import { cookies } from 'next/headers'
import { Database } from './database.types'

export default function useSupabaseServer(cookieStore: ReturnType<typeof cookies>) {
  return createServerClient<Database>(
    process.env.NEXT_PUBLIC_SUPABASE_URL!,
    process.env.NEXT_PUBLIC_SUPABASE_ANON_KEY!,
    {
      cookies: {
        get(name: string) {
          return cookieStore.get(name)?.value
        },
      },
    }
  )
}
```

