### Implement Supabase Client-Side Authentication in Next.js React Components

Source: https://github.com/supabase/supabase/blob/master/apps/docs/content/guides/auth/auth-helpers/nextjs.mdx

This code provides a full client-side React component for user authentication in a Next.js application using Supabase auth helpers. It demonstrates how to sign up, sign in, and sign out users by integrating with the `createClientComponentClient` and handling user input via React `useState` hooks. The component relies on `@supabase/auth-helpers-nextjs` for client creation and `next/navigation` for routing.

```jsx
'use client'\n\nimport { createClientComponentClient } from '@supabase/auth-helpers-nextjs'\nimport { useRouter } from 'next/navigation'\nimport { useState } from 'react'\n\nexport default function Login() {\n  const [email, setEmail] = useState('')\n  const [password, setPassword] = useState('')\n  const router = useRouter()\n  const supabase = createClientComponentClient()\n\n  const handleSignUp = async () => {\n    await supabase.auth.signUp({\n      email,\n      password,\n      options: {\n        emailRedirectTo: `${location.origin}/auth/callback`,\n      },\n    })\n    router.refresh()\n  }\n\n  const handleSignIn = async () => {\n    await supabase.auth.signInWithPassword({\n      email,\n      password,\n    })\n    router.refresh()\n  }\n\n  const handleSignOut = async () => {\n    await supabase.auth.signOut()\n    router.refresh()\n  }\n\n  return (\n    <>\n      <input name="email" onChange={(e) => setEmail(e.target.value)} value={email} />\n      <input\n        type="password"\n        name="password"\n        onChange={(e) => setPassword(e.target.value)}\n        value={password}\n      />\n      <button onClick={handleSignUp}>Sign up</button>\n      <button onClick={handleSignIn}>Sign in</button>\n      <button onClick={handleSignOut}>Sign out</button>\n    </>\n  )\n}
```

